INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", "だが怪我の功名、\n探していた部品を\n偶然にも発見できた", "", 10, "", "", 111031, 11, 302, 13020019, "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", "", "", "", "", "", 5, 93, 302, 13020020, "");
