INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", "存外意義あるものだ\n資材ダイビングとか\nいう新種の探索行は", "", 10, "", "", 111031, 11, 302, 13020026, "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 1, "", "", "", "", 0, 91, 302, 13020027, "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", "まあ万一溺れたとて\n後輩たちの誰ぞが\nきっと気付くだろう", "", 10, "", "", 111031, 11, 302, 13020028, "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", 1, "", "", "", "", 0, 91, 302, 13020029, "");
