INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES ("", "む。奥に入りすぎた\nこれは…出られぬ！\n誰かー！　誰か―！", "", 10, "", "", 111031, 11, 302, 13020034, "");
